  function handleClick() {
    if (spinning) return;
    setSpinning(true);
  }
  return (
    <img
      src={aiLogo}
      alt="AI"
      className={`input-ai-logo${spinning ? ' ai-logo-spin' : ''}`}
      onClick={handleClick}
      onAnimationEnd={() => setSpinning(false)}
      style={{ cursor: 'pointer' }}
    />
